const tagMap = {
    "esteira01/MotorLigado": {
        device: "esteira01",
        metric: "Control/MotorLigado",
        type: "boolean",
        scale: 1
    },
    "esteira01/VelocidadeRPM": {
        device: "esteira01",
        metric: "Process/VelocidadeRPM",
        type: "float",
        scale: 1
    },
    "esteira01/TemperaturaMotor": {
        device: "esteira01",
        metric: "Process/TemperaturaMotor",
        type: "float",
        scale: 10
    },
    "esteira01/ContadorGarrafas": {
        device: "esteira01",
        metric: "Production/ContadorGarrafas",
        type: "int",
        scale: 1
    },
    "esteira01/SensorPresenca": {
        device: "esteira01",
        metric: "Sensor/SensorPresenca",
        type: "boolean",
        scale: 1
    },
    "esteira01/AlarmeSobrecarga": {
        device: "esteira01",
        metric: "Alarm/Sobrecarga",
        type: "boolean",
        scale: 1
    },

    "tanque01/NivelTanque": {
        device: "tanque01",
        metric: "Process/NivelTanque",
        type: "float",
        scale: 10
    },
    "tanque01/BombaLigada": {
        device: "tanque01",
        metric: "Control/BombaLigada",
        type: "boolean",
        scale: 1
    },
    "tanque01/ValvulaEntrada": {
        device: "tanque01",
        metric: "Control/ValvulaEntrada",
        type: "boolean",
        scale: 1
    },
    "tanque01/AlarmeNivelBaixo": {
        device: "tanque01",
        metric: "Alarm/NivelBaixo",
        type: "boolean",
        scale: 1
    },
    "tanque01/AlarmeNivelAlto": {
        device: "tanque01",
        metric: "Alarm/NivelAlto",
        type: "boolean",
        scale: 1
    }
};

const config = tagMap[msg.topic];

if (!config) {
    node.warn(`Tag não mapeada: ${msg.topic}`);
    return null;
}

let raw = Array.isArray(msg.payload) ? msg.payload[0] : msg.payload;
let value;

if (config.type === "boolean") {
    value = Boolean(raw);
} else if (config.type === "int") {
    value = parseInt(raw, 10);
} else if (config.type === "float") {
    value = Number(raw) / config.scale;
} else {
    value = raw;
}

const sparkplugMessage = {
    payload: {
        metrics: [
            {
                name: config.metric,
                value: value,
                timestamp: new Date()
            }
        ]
    }
};

// Saída 1: esteira01
// Saída 2: tanque01
if (config.device === "esteira01") {
    return [sparkplugMessage, null];
}

if (config.device === "tanque01") {
    return [null, sparkplugMessage];
}

return null;

// Function: Gerar leituras Modbus conforme JSON da planta

const UNIT_ID = 1;
const DELAY_MS = 100;
const originalPayload = msg.payload;

const reads = [
    {
        topic: "esteira01/input_register/10",
        fc: 4,
        address: 10,
        quantity: 2
    },
    {
        topic: "esteira01/holding_register/20",
        fc: 3,
        address: 20,
        quantity: 1
    },
    {
        topic: "esteira01/coil/1",
        fc: 1,
        address: 1,
        quantity: 1
    },
    {
        topic: "esteira01/discrete_input/1",
        fc: 2,
        address: 1,
        quantity: 1
    },
    {
        topic: "esteira01/coil/10",
        fc: 1,
        address: 10,
        quantity: 1
    },
    {
        topic: "tanque01/input_register/30",
        fc: 4,
        address: 30,
        quantity: 1
    },
    {
        topic: "tanque01/coil/2",
        fc: 1,
        address: 2,
        quantity: 2
    },
    {
        topic: "tanque01/coil/11",
        fc: 1,
        address: 11,
        quantity: 2
    }
];

reads.forEach((read, index) => {
    setTimeout(() => {
        node.send({
            topic: read.topic,
            payload: {
                value: originalPayload,
                fc: read.fc,
                unitid: UNIT_ID,
                address: read.address,
                quantity: read.quantity
            }
        });
    }, index * DELAY_MS);
});

return null;

// Function: Decodificar Modbus conforme JSON da planta

const groups = {
    "esteira01/input_register/10": {
        equipment: "esteira01",
        table: "input_register",
        baseAddress: 10,
        tags: [
            {
                address: 10,
                tag: "VelocidadeRPM",
                metric: "Process/VelocidadeRPM",
                type: "float",
                scale: 1,
                unit: "RPM"
            },
            {
                address: 11,
                tag: "TemperaturaMotor",
                metric: "Process/TemperaturaMotor",
                type: "float",
                scale: 10,
                unit: "°C"
            }
        ]
    },

    "esteira01/holding_register/20": {
        equipment: "esteira01",
        table: "holding_register",
        baseAddress: 20,
        tags: [
            {
                address: 20,
                tag: "ContadorGarrafas",
                metric: "Production/ContadorGarrafas",
                type: "int",
                scale: 1,
                unit: "un"
            }
        ]
    },

    "esteira01/coil/1": {
        equipment: "esteira01",
        table: "coil",
        baseAddress: 1,
        tags: [
            {
                address: 1,
                tag: "MotorLigado",
                metric: "Control/MotorLigado",
                type: "boolean",
                scale: 1,
                unit: null
            }
        ]
    },

    "esteira01/discrete_input/1": {
        equipment: "esteira01",
        table: "discrete_input",
        baseAddress: 1,
        tags: [
            {
                address: 1,
                tag: "SensorPresenca",
                metric: "Sensor/SensorPresenca",
                type: "boolean",
                scale: 1,
                unit: null
            }
        ]
    },

    "esteira01/coil/10": {
        equipment: "esteira01",
        table: "coil",
        baseAddress: 10,
        tags: [
            {
                address: 10,
                tag: "AlarmeSobrecarga",
                metric: "Alarm/Sobrecarga",
                type: "boolean",
                scale: 1,
                unit: null
            }
        ]
    },

    "tanque01/input_register/30": {
        equipment: "tanque01",
        table: "input_register",
        baseAddress: 30,
        tags: [
            {
                address: 30,
                tag: "NivelTanque",
                metric: "Process/NivelTanque",
                type: "float",
                scale: 10,
                unit: "%"
            }
        ]
    },

    "tanque01/coil/2": {
        equipment: "tanque01",
        table: "coil",
        baseAddress: 2,
        tags: [
            {
                address: 2,
                tag: "BombaLigada",
                metric: "Control/BombaLigada",
                type: "boolean",
                scale: 1,
                unit: null
            },
            {
                address: 3,
                tag: "ValvulaEntrada",
                metric: "Control/ValvulaEntrada",
                type: "boolean",
                scale: 1,
                unit: null
            }
        ]
    },

    "tanque01/coil/11": {
        equipment: "tanque01",
        table: "coil",
        baseAddress: 11,
        tags: [
            {
                address: 11,
                tag: "AlarmeNivelBaixo",
                metric: "Alarm/NivelBaixo",
                type: "boolean",
                scale: 1,
                unit: null
            },
            {
                address: 12,
                tag: "AlarmeNivelAlto",
                metric: "Alarm/NivelAlto",
                type: "boolean",
                scale: 1,
                unit: null
            }
        ]
    }
};

const group = groups[msg.topic];

if (!group) {
    node.warn("Grupo Modbus não mapeado: " + msg.topic);
    return null;
}

function extractValues(msg) {
    const payload = msg.payload;

    if (Array.isArray(payload)) {
        return payload;
    }

    if (payload && Array.isArray(payload.data)) {
        return payload.data;
    }

    if (payload && Array.isArray(payload.buffer)) {
        return payload.buffer;
    }

    if (payload && payload.responseBuffer && Array.isArray(payload.responseBuffer.buffer)) {
        return payload.responseBuffer.buffer;
    }

    if (payload && payload.responseBuffer && Array.isArray(payload.responseBuffer.valuesAsArray)) {
        return payload.responseBuffer.valuesAsArray;
    }

    if (msg.responseBuffer && Array.isArray(msg.responseBuffer.buffer)) {
        return msg.responseBuffer.buffer;
    }

    if (msg.responseBuffer && Array.isArray(msg.responseBuffer.valuesAsArray)) {
        return msg.responseBuffer.valuesAsArray;
    }

    if (msg.modbusResponse && Array.isArray(msg.modbusResponse.data)) {
        return msg.modbusResponse.data;
    }

    return [payload];
}

function convertValue(raw, type, scale) {
    if (type === "boolean") {
        return Boolean(raw);
    }

    if (type === "int") {
        return parseInt(raw, 10);
    }

    if (type === "float") {
        return Number(raw) / scale;
    }

    return raw;
}

const values = extractValues(msg);
const output = [];

for (const tag of group.tags) {
    const index = tag.address - group.baseAddress;
    const raw = values[index];

    if (raw === undefined) {
        node.warn(`Sem valor para ${group.equipment}/${tag.tag} no índice ${index}`);
        continue;
    }

    output.push({
        topic: `${group.equipment}/${tag.tag}`,
        payload: {
            equipment: group.equipment,
            tag: tag.tag,
            metric: tag.metric,
            table: group.table,
            address: tag.address,
            raw_value: raw,
            value: convertValue(raw, tag.type, tag.scale),
            type: tag.type,
            unit: tag.unit,
            timestamp: new Date().toISOString()
        }
    });
}

return [output];

// Function: Tag normalizada -> Sparkplug B
//
// Entrada esperada:
// msg.payload = {
//   equipment: "esteira01",
//   tag: "TemperaturaMotor",
//   metric: "Process/TemperaturaMotor",
//   value: 25,
//   raw_value: 250,
//   type: "float",
//   unit: "°C"
// }
//
// Saída esperada para mqtt sparkplug device:
// msg.payload = {
//   metrics: [
//     {
//       name: "Process/TemperaturaMotor",
//       value: 25,
//       timestamp: Date
//     }
//   ]
// }

const data = msg.payload || {};

const equipment = data.equipment || "unknown_device";
const metricName = data.metric || data.tag || msg.topic || "unknown_metric";

let value = data.value;

// Normaliza tipos
if (data.type === "boolean") {
    value = Boolean(value);
} else if (data.type === "int") {
    value = parseInt(value, 10);
} else if (data.type === "float") {
    value = Number(value);
}

// Evita publicar valores inválidos
if (value === undefined || value === null || Number.isNaN(value)) {
    node.warn("Valor inválido para Sparkplug: " + JSON.stringify(data));
    return null;
}

// Metadados auxiliares para o switch e debug
msg.device = equipment;
msg.topic = `${equipment}/${metricName}`;

msg.payload = {
    metrics: [
        {
            name: metricName,
            value: value,
            timestamp: new Date()
        }
    ]
};

return msg;

const topic = msg.topic || "";
const parts = topic.split("/");

// Esperado:
// spBv1.0/avila/DDATA/gateway_node_01/esteira01
const namespace = parts[0] || "";
const groupId = parts[1] || "";
const messageType = parts[2] || "";
const edgeNodeId = parts[3] || "";
const deviceId = parts[4] || "unknown_device";

if (messageType !== "DDATA") {
    return null;
}

const payload = msg.payload || {};
const metrics = payload.metrics || [];

const points = [];

for (const metric of metrics) {
    if (!metric.name) {
        continue;
    }

    let value = metric.value;

    if (value === undefined || value === null) {
        continue;
    }

    if (typeof value === "boolean") {
        value = value ? 1 : 0;
    }

    if (typeof value === "string") {
        continue;
    }

    const metricParts = metric.name.split("/");
    const metricGroup = metricParts.length > 1 ? metricParts[0] : "General";
    const metricName = metricParts.length > 1
        ? metricParts.slice(1).join("/")
        : metric.name;

    points.push({
        measurement: "plc_metrics",
        tags: {
            namespace: namespace,
            group_id: groupId,
            edge_node_id: edgeNodeId,
            device: deviceId,
            metric_group: metricGroup,
            metric: metricName,
            metric_full_name: metric.name
        },
        fields: {
            value: Number(value)
        },
        timestamp: new Date()
    });
}

if (points.length === 0) {
    return null;
}

msg.payload = points;

return msg;
